    var found := false;
    for j := 0 to |b| {
      if a[i] == b[j] { found := true; }
    }
    if !found { return false; }
  }
  for i := 0 to |b| {
    var found := false;
    for j := 0 to |a| {
      if b[i] == a[j] { found := true; }
    }
    if !found { return false; }
  }
  return true;
}
